package com.museumheist.game;public final class LevelScoring{private LevelScoring(){}public static int calculateStars(boolean has,boolean all,float elapsed,int alerts){if(!has)return 0;if(!all)return 1;return elapsed<=GameConfig.THREE_STAR_TIME_SECONDS&&alerts==0?3:2;}public static int calculateRewardCoins(int stars,int run){int s=Math.max(0,Math.min(3,stars));return GameConfig.CLEAR_COIN_REWARD+s*GameConfig.STAR_COIN_REWARD+(s==3?GameConfig.PERFECT_COIN_REWARD:0)+Math.max(0,run);}}
